import { useState, useMemo, useCallback, useRef } from "react"
import { ColDef, ICellRendererParams } from "ag-grid-community"
import { AgGridReact } from "ag-grid-react"
import { Button, message, Popconfirm, Form, Space } from "antd"
import UsersForm from "./components/users_form"
import { DeleteOutlined, EditOutlined } from "@ant-design/icons"
import { useTranslation } from "../../../shared/lib/providers/i18n-provider"
import DataGrid from "../../../shared/components/DataGrid/DataGrid"
import { initialData, IUser } from "../models/user_model"

export default function Users() {
  const { locale, t } = useTranslation()
  const gridRef = useRef<AgGridReact>(null)
  const [rowData, setRowData] = useState<IUser[]>(initialData)
  const [isModalVisible, setIsModalVisible] = useState(false)
  const [editingRow, setEditingRow] = useState<IUser | null>(null)
  const [form] = Form.useForm()

  const handleAdd = () => {
    setEditingRow(null)
    form.resetFields()
    setIsModalVisible(true)
  }

  const handleEdit = useCallback(
    (data: IUser) => {
      setEditingRow(data)
      form.setFieldsValue(data)
      setIsModalVisible(true)
    },
    [form]
  )

  const handleDelete = useCallback(() => {
    message.success(t("deleteSuccess"))
  }, [t])

  const ActionRenderer = useCallback(
    (params: ICellRendererParams) => (
      <Space>
        <Button type="text" icon={<EditOutlined />} onClick={() => handleEdit(params.data)} />
        <Popconfirm title={t("confirmDeleteUser")} onConfirm={() => handleDelete()}>
          <Button type="text" danger icon={<DeleteOutlined />} />
        </Popconfirm>
      </Space>
    ),
    [t, handleEdit, handleDelete]
  )

  const columnDefs: ColDef<IUser>[] = useMemo(
    () => [
      { field: "id", headerName: t("id"), chartDataType: "excluded" },
      {
        field: "name",
        headerName: t("name"),
        chartDataType: "category"
      },
      {
        field: "email",
        headerName: t("email"),
        chartDataType: "category"
      },
      {
        field: "role",
        headerName: t("role"),
        cellRenderer: (params: ICellRendererParams) =>
          t(params.value?.toLowerCase()) || params.value,
        cellEditor: "agSelectCellEditor",
        cellEditorParams: { values: ["Admin", "User", "Editor"] },
        chartDataType: "category"
      },
      {
        field: "status",
        headerName: t("status"),
        cellRenderer: (params: ICellRendererParams) => (
          <span style={{ color: params.value === 1 ? "green" : "red", fontWeight: "bold" }}>
            {params.value === 1 ? t("active") : t("inactive")}
          </span>
        ),
        chartDataType: "series"
      },
      { field: "loginCount", headerName: t("loginCount"), chartDataType: "series" },
      { field: "lastLogin", headerName: t("lastLogin"), chartDataType: "excluded" },
      {
        headerName: t("actions"),
        cellRenderer: ActionRenderer,
        suppressHeaderMenuButton: true,
        sortable: false,
        filter: false,
        pinned: locale === "ar" ? "left" : "right",
        chartDataType: "excluded"
      }
    ],
    [t, ActionRenderer, locale]
  )

  const handleModalOk = () => {
    form.validateFields().then((values) => {
      if (editingRow) {
        setRowData((prev) =>
          prev.map((row) => (row.id === editingRow.id ? { ...row, ...values } : row))
        )
        message.success(t("updateSuccess"))
      } else {
        const newId = (Math.max(...rowData.map((r) => parseInt(r.id)), 0) + 1).toString()
        const newUser: IUser = {
          id: newId,
          lastLogin: new Date().toISOString().split("T")[0],
          ...values
        }
        setRowData((prev) => [...prev, newUser])
        message.success(t("createSuccess"))
      }
      setIsModalVisible(false)
    })
  }

  return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", gap: 16 }}>
      <div id="myGrid" style={{ flex: 1, minHeight: 500 }}>
        <DataGrid
          ref={gridRef}
          rowData={rowData}
          columnDefs={columnDefs}
          onAdd={handleAdd}
          showSideMenu={true}
          addText={t("addUser")}
          showExport={true}
          showPrint={true}
          initialFilters={[
            { colId: "status", filter: "agSetColumnFilter", filterParams: { values: [0, 1] } },
            {
              colId: "role",
              filter: "agSetColumnFilter",
              filterParams: { values: ["Admin", "User", "Editor"] }
            }
          ]}
        />
      </div>

      <UsersForm
        open={isModalVisible}
        editingRow={editingRow}
        form={form}
        onOk={handleModalOk}
        onCancel={() => setIsModalVisible(false)}
      />
    </div>
  )
}
