/* eslint-disable @typescript-eslint/no-explicit-any */
import React, { useMemo, forwardRef, useState, useCallback } from "react"
import { AgGridReact, AgGridReactProps } from "ag-grid-react"
import {
  ModuleRegistry,
  ClientSideRowModelModule,
  PaginationModule,
  ValidationModule,
  TextFilterModule,
  NumberFilterModule,
  DateFilterModule,
  TextEditorModule,
  SelectEditorModule,
  RowSelectionModule,
  QuickFilterModule,
  themeQuartz,
  colorSchemeDarkBlue,
  colorSchemeLight,
  GridApi,
  GridReadyEvent
} from "ag-grid-community"
import {
  IntegratedChartsModule,
  ClipboardModule,
  ColumnsToolPanelModule,
  FiltersToolPanelModule,
  NewFiltersToolPanelModule,
  MultiFilterModule,
  MenuModule,
  CellSelectionModule,
  ExcelExportModule,
  CsvExportModule,
  SparklinesModule,
  StatusBarModule,
  RowGroupingModule,
  SetFilterModule,
  PivotModule,
  LocaleModule,
  RowGroupingPanelModule
} from "ag-grid-enterprise"
import { AgChartsEnterpriseModule } from "ag-charts-enterprise"
import { AG_GRID_LOCALE_EG } from "@ag-grid-community/locale"
import { useTheme } from "../../lib/providers/theme-provider"
import { useTranslation } from "../../lib/providers/i18n-provider"
import { Button, Space, Input, Dropdown, MenuProps, Layout } from "antd"
import {
  ClearOutlined,
  SearchOutlined,
  PlusOutlined,
  FileExcelOutlined,
  PrinterOutlined,
  SettingOutlined
} from "@ant-design/icons"
import type { MenuProps as AntMenuProps } from "antd"

ModuleRegistry.registerModules([
  ClientSideRowModelModule,
  PaginationModule,
  TextFilterModule,
  NumberFilterModule,
  DateFilterModule,
  SetFilterModule,
  TextEditorModule,
  SelectEditorModule,
  RowSelectionModule,
  PivotModule,
  IntegratedChartsModule.with(AgChartsEnterpriseModule),
  ValidationModule,
  ClipboardModule,
  ColumnsToolPanelModule,
  FiltersToolPanelModule,
  NewFiltersToolPanelModule,
  MultiFilterModule,
  MenuModule,
  CellSelectionModule,
  ExcelExportModule,
  CsvExportModule,
  SparklinesModule.with(AgChartsEnterpriseModule),
  StatusBarModule,
  RowGroupingModule,
  LocaleModule,
  QuickFilterModule,
  RowGroupingPanelModule
])

interface DataGridProps extends AgGridReactProps {
  initialFilters?: any
  onAdd?: () => void
  showExport?: boolean
  showPrint?: boolean
  addText?: string
  sideMenuItems?: AntMenuProps["items"]
  showSideMenu?: boolean
  onMenuClick?: (key: string) => void
}

const DataGrid = forwardRef<AgGridReact, DataGridProps>((props, ref) => {
  const { t, locale } = useTranslation()
  const { theme } = useTheme()
  const [quickFilterText, setQuickFilterText] = useState("")
  const [gridApi, setGridApi] = useState<GridApi | null>(null)
  const [hasActiveFilters, setHasActiveFilters] = useState(false)

  const gridTheme = useMemo(() => {
    if (theme === "dark") {
      return themeQuartz
        .withPart(colorSchemeDarkBlue)
        .withParams({ backgroundColor: "var(--white-100)" })
    }
    return themeQuartz.withPart(colorSchemeLight)
  }, [theme])

  const defaultSideBar = useMemo(
    () => ({
      toolPanels: [
        {
          id: "columns",
          labelDefault: "Columns",
          labelKey: "columns",
          iconKey: "columns",
          toolPanel: "agColumnsToolPanel",
          minWidth: 250,
          width: 250,
          maxWidth: 400
        },
        {
          id: "filters",
          labelDefault: "Filters",
          labelKey: "filters",
          iconKey: "filter",
          toolPanel: "agNewFiltersToolPanel",
          toolPanelParams: {
            filters: props.initialFilters,
            suppressSetFilterByDefault: true
          },
          minWidth: 180,
          maxWidth: 400,
          width: 250
        }
      ],
      position: "left" as "left" | "right",
      defaultToolPanel: ""
    }),
    [props.initialFilters]
  )

  const defaultColDef = useMemo(
    () => ({
      sortable: true,
      filter: true,
      resizable: true,
      enableRowGroup: true,
      enableValue: true,
      enablePivot: true,
      floatingFilter: true,
      filterParams: { buttons: ["clear"] },
      ...props.defaultColDef,

    }),
    [props.defaultColDef]
  )

  const handleClearAllFilters = useCallback(() => {
    if (gridApi) gridApi.setFilterModel(null)
  }, [gridApi])

  const defaultStatusBar = useMemo(
    () => ({
      statusPanels: [
        { statusPanel: "agTotalAndFilteredRowCountComponent", align: "left" },
        { statusPanel: "agSelectedRowCountComponent", align: "left" }
      ]
    }),
    []
  )

  const getContextMenuItems = useMemo(() => {
    return () =>
      [
        "copy",
        "copyWithHeaders",
        "paste",
        "separator",
        "chartRange",
        "separator",
        "export"
      ] as any[]
  }, [])

  const handleExport = useCallback(() => {
    if (gridApi) gridApi.exportDataAsExcel()
  }, [gridApi])

  const handlePrint = useCallback(() => {
    if (gridApi) {
      gridApi.setGridOption("domLayout", "print")
      setTimeout(() => {
        window.print()
        gridApi.setGridOption("domLayout", "normal")
      }, 500)
    }
  }, [gridApi])

  const checkActiveFilters = useCallback((api: GridApi) => {
    const model = api.getFilterModel()
    setHasActiveFilters(Object.keys(model).length > 0)
  }, [])

  const onGridReady = useCallback(
    (event: GridReadyEvent) => {
      setGridApi(event.api)
      checkActiveFilters(event.api)
      if (props.onGridReady) props.onGridReady(event)
    },
    [props, checkActiveFilters]
  )

  const onFilterChanged = useCallback(
    (event: any) => {
      checkActiveFilters(event.api)
      if (props.onFilterChanged) props.onFilterChanged(event)
    },
    [props, checkActiveFilters]
  )

  const menuItems: MenuProps["items"] = useMemo(
    () =>
      [
        props.showExport && {
          key: "export",
          label: t("exportExcel"),
          icon: <FileExcelOutlined />,
          onClick: handleExport
        },
        props.showPrint && {
          key: "print",
          label: t("print"),
          icon: <PrinterOutlined />,
          onClick: handlePrint
        }
      ].filter(Boolean) as MenuProps["items"],
    [props.showExport, props.showPrint, handleExport, handlePrint, t]
  )

  const gridContent = (
    <div
      className="ag-theme-quartz"
      style={{
        width: "100%",
        height: "100%",
        display: "flex",
        flexDirection: "column",
        gap: "12px"
      }}>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          padding: "4px 0"
        }}>
        <Input
          placeholder={t("search")}
          prefix={<SearchOutlined style={{ color: "var(--caption-500)" }} />}
          value={quickFilterText}
          onChange={(e) => setQuickFilterText(e.target.value)}
          style={{
            width: 320,
            borderRadius: "10px",
            height: "40px",
            boxShadow: "0 2px 8px var(--caption-50)"
          }}
          allowClear
        />
        <Space size="middle">
          {hasActiveFilters && (
            <Button
              icon={<ClearOutlined />}
              onClick={handleClearAllFilters}
              type="text"
              danger
              style={{ height: "40px", borderRadius: "10px", fontWeight: 500 }}>
              {t("clearFilters")}
            </Button>
          )}
          {props.onAdd && (
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={props.onAdd}
              style={{
                borderRadius: "10px",
                height: "40px",
                padding: "0 24px",
                fontWeight: 600,
                boxShadow: "0 2px 8px rgba(24, 144, 255, 0.2)"
              }}>
              {props.addText || t("add")}
            </Button>
          )}
          <Dropdown
            menu={{ items: menuItems }}
            placement="bottomRight"
            trigger={["click"]}
            disabled={!props.showExport && !props.showPrint}>
            <Button
              icon={<SettingOutlined />}
              style={{
                borderRadius: "10px",
                height: "40px",
                width: "40px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center"
              }}
            />
          </Dropdown>
        </Space>
      </div>
      <div style={{ flex: 1, borderRadius: "12px" }}>
        <AgGridReact
          ref={ref}
          theme={gridTheme}
          enableRtl={locale === "ar"}
          localeText={locale === "ar" ? AG_GRID_LOCALE_EG : props.localeText}
          sideBar={props.sideBar === undefined ? defaultSideBar : props.sideBar}
          statusBar={props.statusBar === undefined ? defaultStatusBar : props.statusBar}
          defaultColDef={defaultColDef}
          quickFilterText={quickFilterText}
          enableFilterHandlers={true}
          suppressSetFilterByDefault={true}
          pagination={props.pagination ?? true}
          paginationPageSize={props.paginationPageSize ?? 10}
          paginationPageSizeSelector={props.paginationPageSizeSelector ?? [10, 20, 50]}
          rowSelection={
            props.rowSelection ?? { mode: "multiRow", checkboxes: false, headerCheckbox: false }
          }
          rowGroupPanelShow="always"
          cellSelection={props.cellSelection ?? true}
          enableCharts={props.enableCharts ?? true}
          allowContextMenuWithControlKey={true}
          chartToolPanelsDef={props.chartToolPanelsDef ?? { defaultToolPanel: "settings" }}
          getContextMenuItems={getContextMenuItems}
          popupParent={document.body}
          onGridReady={onGridReady}
          onFilterChanged={onFilterChanged}
          {...props}
        />
      </div>
    </div>
  )

  if (props.showSideMenu) {
    return (
      <Layout style={{ height: "100%", background: "transparent" }}>
        <Layout style={{ background: "transparent" }}>{gridContent}</Layout>
      </Layout>
    )
  }

  return gridContent
})

DataGrid.displayName = "DataGrid"

export default DataGrid
