import { Modal, Form, Input, Select } from "antd"
import { useTranslation } from "../../../../shared/lib/providers/i18n-provider"
import { IUser } from "../../models/user_model"

interface UsersFormProps {
  open: boolean
  editingRow: IUser | null
  form: ReturnType<typeof Form.useForm>[0]
  onOk: () => void
  onCancel: () => void
}

export default function UsersForm({ open, editingRow, form, onOk, onCancel }: UsersFormProps) {
  const { t } = useTranslation()

  return (
    <Modal
      title={editingRow ? t("editUser") : t("addUser")}
      open={open}
      onOk={onOk}
      centered
      onCancel={onCancel}>
      <Form form={form} layout="vertical">
        <Form.Item name="name" label={t("name")} rules={[{ required: true }]}>
          <Input />
        </Form.Item>
        <Form.Item name="email" label={t("email")} rules={[{ required: true, type: "email" }]}>
          <Input />
        </Form.Item>
        <Form.Item name="role" label={t("role")} rules={[{ required: true }]}>
          <Select
            options={[
              { value: "Admin", label: t("admin") },
              { value: "User", label: t("user") },
              { value: "Editor", label: t("editor") },
            ]}
          />
        </Form.Item>
        <Form.Item name="status" label={t("status")} rules={[{ required: true }]}>
          <Select
            options={[
              { value: "Active", label: t("active") },
              { value: "Inactive", label: t("inactive") },
            ]}
          />
        </Form.Item>
      </Form>
    </Modal>
  )
}
